/**
 * Mock data for Growth · Email Campaigns.
 *
 * Each row is a one-time send. Page is read-only: claimed-vs-verified
 * revenue (the platform always over-reports), net after list cost, and
 * the verdict — paid off, thin, cost you. Profit chain at top shows the
 * walk from verified revenue → CM3.
 */

export type EmailVerdict = "green" | "amber" | "red" | "grey";

export interface EmailCampaignRow {
  id: string;
  name: string;
  date: string;
  /** Audience segment label. */
  seg: string;
  recip: string;
  open: string;
  click: string;
  claimed: string;
  ver: string;
  /** "↓ 29% air" or "" if no air. */
  air: string;
  airCls: "over" | "";
  net: string;
  cm3: string;
  unsub: string;
  unsubPct: string;
  verdict: string;
  v: EmailVerdict;
  /** Previous-period delta line. */
  prev: string;
  prevCls: "up" | "down" | "";
  /** CSS gradient for the thumbnail. */
  thumb: string;
  /** Scheduled rows render in muted style. */
  sched?: boolean;
}

