"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  EMAIL_CAMPAIGNS,
  emailMetrics,
  emailProfitChain,
  emailAI,
  type EmailCampaignRow,
} from "@/features/growth/api/growth-email-campaigns-data";
import "./email-campaigns.css";

const PERIOD_LABELS = ["Last 30 days", "Last 90 days", "Year to date"];

const num = (s: string) => {
  if (!s || s === "—") return -Infinity;
  const m = s.replace(/[,$%]/g, "").match(/-?\d+(?:\.\d+)?/);
  if (!m) return -Infinity;
  let v = parseFloat(m[0]);
  if (/k/i.test(s)) v *= 1000;
  if (/m/i.test(s)) v *= 1_000_000;
  return v;
};

type SortKey = "name" | "open" | "click" | "claimed" | "ver" | "net" | "unsub";

const imageIcon = (
  <svg className="ic" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <rect x="3" y="4" width="18" height="16" rx="2" />
    <circle cx="8.5" cy="9.5" r="1.6" />
    <path d="M4 18 L9 13 L13 16 L17 11 L20 14" />
  </svg>
);

export default function EmailCampaignsPage() {
  const [periodIdx, setPeriodIdx] = useState(1);
  const [sortKey, setSortKey] = useState<SortKey>("ver");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const [search, setSearch] = useState("");
  const { openBridge } = useBridge();

  const rows = useMemo(() => {
    const live = EMAIL_CAMPAIGNS.filter((c) => !c.sched);
    const sched = EMAIL_CAMPAIGNS.filter((c) => c.sched);
    const q = search.toLowerCase().trim();
    const filtered = q
      ? live.filter(
          (c) =>
            c.name.toLowerCase().includes(q) || c.seg.toLowerCase().includes(q),
        )
      : live;
    filtered.sort((a, b) => {
      if (sortKey === "name") return sortDir * a.name.localeCompare(b.name);
      const av = num(a[sortKey]);
      const bv = num(b[sortKey]);
      return sortDir * (av - bv);
    });
    return [...filtered, ...sched];
  }, [sortKey, sortDir, search]);

  const onSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "name" ? 1 : -1);
    }
  };

  const col = (k: SortKey | "verdict" | "thumb", label: React.ReactNode, opts: { r?: boolean; sortable?: boolean } = {}) => {
    const { r = false, sortable = true } = opts;
    const active = sortable && sortKey === k;
    return (
      <div
        className={`c${r ? " r" : ""}${active ? " active" : ""}${sortKey === "ver" && k === "ver" ? " vhead" : ""}`}
        onClick={sortable ? () => onSort(k as SortKey) : undefined}
        style={!sortable ? { cursor: "default" } : undefined}
      >
        {k === "ver" && sortable && <span className="hmark" />}
        {label}
        {sortable && <span className="sort-ar">{active && sortDir < 0 ? "↓" : "↑"}</span>}
      </div>
    );
  };

  return (
    <div className="growth-email-campaigns-page">
      <DeptHeader
        dept="growth"
        title="Email Campaigns"
        meta={
          <>
            <span className="live">Live</span> · One-time sends · verified revenue, net of list cost
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("growth")}
            >
              Plan next send →
            </button>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} accent="var(--d-growth)" />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Campaigns sent</div>
          <div className="metric-v">{emailMetrics.campaignsSent}</div>
          <div className="metric-s">{emailMetrics.campaignsSentSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Verified revenue</div>
          <div className="metric-v green">{emailMetrics.verifiedRevenue}</div>
          <div className="metric-s">{emailMetrics.verifiedRevenueSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Avg open rate</div>
          <div className="metric-v">{emailMetrics.openRate}</div>
          <div className="metric-s">{emailMetrics.openRateSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Discount reliance</div>
          <div className="metric-v amber">{emailMetrics.discountReliance}</div>
          <div className="metric-s">{emailMetrics.discountRelianceSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Audience cost</div>
          <div className="metric-v red">{emailMetrics.audienceCost}</div>
          <div className="metric-s">{emailMetrics.audienceCostSub}</div>
        </div>
      </div>

      {/* Profit chain */}
      <div className="profit-chain">
        <div className="pc-head">What email actually contributed — verified revenue down to profit</div>
        <div className="pc-flow">
          <div className="pc-stage">
            <div className="lbl"><span className="pc-vmark" />Verified revenue</div>
            <div className="val">{emailProfitChain.verifiedRevenue}</div>
            <div className="sub">{emailProfitChain.verifiedSub}</div>
          </div>
          <div className="pc-gap">
            <div className="minus">{emailProfitChain.listCost}</div>
            <div className="conn" />
          </div>
          <div className="pc-stage">
            <div className="lbl">Net of list cost</div>
            <div className="val">{emailProfitChain.netOfListCost}</div>
            <div className="sub">{emailProfitChain.netSub}</div>
          </div>
          <div className="pc-gap">
            <div className="minus">{emailProfitChain.productAndFulfillment}</div>
            <div className="conn" />
          </div>
          <div className="pc-stage">
            <div className="lbl">To contribution margin</div>
            <div className="val green">{emailProfitChain.cm3}</div>
            <div className="sub">{emailProfitChain.cm3Sub}</div>
          </div>
        </div>
      </div>

      <AIStrip label={emailAI.label} meta={emailAI.meta} cards={emailAI.cards} />

      {/* Ledger */}
      <SectionLabel>Every send — what the platform claimed, what your orders verify, and what it netted</SectionLabel>
      <div className="search-row">
        <div className="search-box">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="11" cy="11" r="7" />
            <line x1="21" y1="21" x2="16.5" y2="16.5" />
          </svg>
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search campaigns or segments..."
          />
        </div>
      </div>

      <div className="camp-table">
        <div className="camp-cols">
          <div className="c" style={{ cursor: "default" }} />
          {col("name", "Campaign")}
          {col("open", "Open", { r: true })}
          {col("click", "Click", { r: true })}
          {col("claimed", "Claimed", { r: true })}
          {col("ver", "Verified", { r: true })}
          {col("net", "Net", { r: true })}
          {col("unsub", "Unsubs", { r: true })}
          {col("verdict", "Verdict", { r: true, sortable: false })}
        </div>
        {rows.map((c) => (
          <CampRow key={c.id} c={c} openBridge={openBridge} />
        ))}
      </div>
    </div>
  );
}

function CampRow({
  c,
  openBridge,
}: {
  c: EmailCampaignRow;
  openBridge: ReturnType<typeof useBridge>["openBridge"];
}) {
  if (c.sched) {
    return (
      <div className={`camp-row v-${c.v} sched`}>
        <div className="c-thumb">
          <div className="ph" style={{ background: c.thumb }} />
          {imageIcon}
        </div>
        <div className="c-name">
          <div className="nm">{c.name}</div>
          <div className="sb">
            {c.date} · {c.seg} · {c.recip} recipients
          </div>
        </div>
        <div className="c-num muted">—</div>
        <div className="c-num muted">—</div>
        <div className="c-num muted">—</div>
        <div className="c-ver">
          <span className="vn" style={{ color: "var(--ink-3)" }}>—</span>
        </div>
        <div className="c-num muted">—</div>
        <div className="c-num muted">—</div>
        <div className="c-verdict-wrap">
          <span className="c-verdict">{c.verdict}</span>
        </div>
        <button
          className="c-bridge"
          type="button"
          onClick={() => openBridge("growth")}
        >
          Edit send →
        </button>
      </div>
    );
  }
  return (
    <div className={`camp-row v-${c.v}`}>
      <div className="c-thumb">
        <div className="ph" style={{ background: c.thumb }} />
        {imageIcon}
      </div>
      <div className="c-name">
        <div className="nm">{c.name}</div>
        <div className="sb">
          {c.date} · {c.seg} · {c.recip} recipients
        </div>
      </div>
      <div className="c-num">{c.open}</div>
      <div className="c-num">{c.click}</div>
      <div className="c-claimed">{c.claimed}</div>
      <div className="c-ver">
        <span className="vn">{c.ver}</span>
        {c.air && <span className="vg">{c.air}</span>}
      </div>
      <div className="c-net">
        <span className="nn">{c.net}</span>
        {c.cm3 && (
          <span className="cm">
            → <b>{c.cm3}</b> CM3
          </span>
        )}
      </div>
      <div className="c-uns">
        <span className="un">{c.unsub}</span>
        {c.unsubPct && <span className="up">{c.unsubPct}</span>}
      </div>
      <div className="c-verdict-wrap">
        <span className="c-verdict">{c.verdict}</span>
        {c.prev && <span className={`c-prev ${c.prevCls}`}>{c.prev}</span>}
      </div>
      <button
        className="c-bridge"
        type="button"
        onClick={() => openBridge("growth")}
      >
        Plan follow-up →
      </button>
    </div>
  );
}
